test_that("ctree_ci rejects negative weights", {
  toy_data <- data.frame(
    rank = c(10, 20, 30, 40),
    outcome = c(1, 0, 1, 0),
    income = c(2, 4, 6, 8)
  )

  expect_error(
    ctree_ci(
      formula = cbind(rank, outcome) ~ income,
      data = toy_data,
      rank_name = "rank",
      outcome_name = "outcome",
      weights = c(1, -1, 1, 1)
    ),
    "weights must be non-negative"
  )
})

